from collections import deque

def minPath(grid, k):
    n = len(grid)
    directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]
    queue = deque([(i, j, set()) for i in range(n) for j in range(n)])
    visited = set((i, j) for i in range(n) for j in range(n))
    while queue:
        x, y, path = queue.popleft()
        if len(path) == k:
            return list(path)
        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if 0 <= nx < n and 0 <= ny < n and (nx, ny) not in visited:
                visited.add((nx, ny))
                queue.append((nx, ny, path | {grid[nx][ny]}))
